VALUES
  ('social-worker-moex-08150', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在連結案主與其他資源系統時，有時候會提供轉介服務，提供轉介服務時有一些原則，以下那 一項是不正確的？', '["傳達對轉介機構的正面評價", "與案主討論所希望得到的服務", "社會工作員提供機構名單，讓案主選擇", "具體說明轉介機構可能採取的行動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08151', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '單親媽媽帶有四個小孩，與社會隔離，靠著低收入補助過生活，最近被通報有兒虐的狀況，請問下列那一 項服務與其問題最沒有關係？', '["轉介到情緒控制的團體", "轉介到親職教育的團體", "轉介到社會支持的團體", "協助尋找低價格住有相類似情況者的住宅地區"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08152', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '充權在實務與宗旨上，是以什麼為最主要目標？', '["以達到社會正義為目標", "強化個人權力意識", "促進人際溝通", "提昇個人能力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08153', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作的過程分為幾個階段，其中以組織居民、設定工作目標、規劃方案與執行作為核心工作的階段是：', '["起步階段", "工作階段", "維持與擴張階段", "永續工作階段"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08154', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '若社區或社區中的部分人口群，受到不公平政策的壓制及剝削，例如，雲林毛巾業者因大陸毛巾傾銷所造 成的影響，此時宜採取的社區工作模式是：', '["地區發展模式", "社會計畫模式", "社會行動模式", "宏觀實務模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08155', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作價值觀很重要，它是社區工作實踐的方向，下列何者非屬社區工作者所抱持的價值觀？', '["社會正義", "領導與統馭", "人有其尊嚴與價值", "人要互助並具社會價值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08156', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '地區發展、社會計畫與社會行動是最被廣泛使用的社區工作模式，其歸納、建構者是：', '["Batten（1967）", "Taylor & Roberts（1985）", "Weil（1996）", "Rothman（1968）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08157', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '1917年出版的第一本社會個案工作的專書－《社會診斷》—作者是：', '["Perlman, H.H", "Richmond, M.E", "Biestek, F", "Dewey, J"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08158', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社區工作的實踐過程中，強調專業團隊進入協助社區居民，發展社區及解決社區問題，並培養、重建社 區居民能力，所秉持的工作原則是：', '["社區參與原則", "民主及自主自決原則", "合作與互助原則", "培力與自立原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08159', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '檢視多項研究後，Wood發現處遇成功的社會工作者，在下列那一項技巧使用上比處遇未成功的社會工作者 來得好？', '["專業關係的建立", "將目標部分化", "善於運用社會資源", "處理案主的抗拒心"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
